module RefModule(clk, we, addr, din, dout);input clk, we;
  input [1:0] addr;
  input [3:0] din;
  output [3:0] dout;

  reg [3:0] ram [0:3];

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (we) begin
      ram[addr] <= din;
    end
  end

  assign dout = ram[addr];

endmodule
